const { MongoClient } = require('mongodb');
const express = require('express');

const app = express();
app.use(express.json());

// Allowlist of supported operators
const allowedOperators = ['$gt', '$lt', '$in', '$regex'];

function queryBuilder(filter, projection, sort) {
  const db = new MongoClient('mongodb://localhost:27017/', { useNewUrlParser: true, useUnifiedTopology: true });
  db.connect((err) => {
    if (err) console.error(err);
  });

  const collection = db.collection('users');

  // Validate filter object
  for (const key in filter) {
    if (!allowedOperators.includes(key)) {
      throw new Error(`Unsupported operator: ${key}`);
    }
  }

  // Validate projection specifications
  for (const key in projection) {
    if (typeof projection[key] !== 'boolean') {
      throw new Error('Projection values must be booleans');
    }
  }

  // Validate sort criteria
  for (const key in sort) {
    if (typeof sort[key] !== 'number') {
      throw new Error('Sort values must be numbers');
    }
  }

  collection.find(filter, { projection }, { sort }).toArray((err, result) => {
    if (err) console.error(err);
    else console.log(result);
  });
}

app.post('/query', (req, res) => {
  const filter = req.body.filter;
  const projection = req.body.projection;
  const sort = req.body.sort;

  try {
    queryBuilder(filter, projection, sort);
    res.send('Query executed successfully');
  } catch (err) {
    res.status(400).send(err.message);
  }
});

app.listen(3000, () => console.log('Server listening on port 3000'));